Add-Type -AssemblyName System.Drawing; $src = 'assets\new_assets\Diapo 02\navi-concept 2.0.jpg'; $dst = 'assets\new_assets\Diapo 02\navi-concept 2.0_web.jpg'; $img = [System.Drawing.Image]::FromFile($src); $newWidth = 1920; $newHeight = [int]($img.Height * ($newWidth / $img.Width)); $bmp = New-Object System.Drawing.Bitmap($newWidth, $newHeight); $graph = [System.Drawing.Graphics]::FromImage($bmp); $graph.InterpolationMode = [System.Drawing.Drawing2D.InterpolationMode]::HighQualityBicubic; $graph.DrawImage($img, 0, 0, $newWidth, $newHeight); $bmp.Save($dst, [System.Drawing.Imaging.ImageFormat]::Jpeg); $graph.Dispose(); $bmp.Dispose(); $img.Dispose(); Write-Output 'Resized'
